11	/** @file   render_sdf.cuh
12	 *  @author Thomas Müller, NVIDIA
13	 */
14	
15	#include <neural-graphics-primitives/bounding_box.cuh>
16	#include <neural-graphics-primitives/common_device.cuh>
17	#include <neural-graphics-primitives/envmap.cuh>
18	#include <neural-graphics-primitives/sdf_device.cuh>
19	#include <neural-graphics-primitives/triangle_octree_device.cuh>
20	
21	using namespace ngp;
22	
23	__global__ void trace_sdf(
24		const ivec2 resolution,
25		const float zero_offset,
26		vec3* __restrict__ positions,
27		float* __restrict__ distances,
28		SdfPayload* __restrict__ payloads,
29		BoundingBox aabb,
30		float floor_y,
31		const TriangleOctreeNode* __restrict__ octree_nodes,
32		int max_octree_depth,
33		float distance_scale,
34		float maximum_distance,
35		float k,
36		float* __restrict__ prev_distances,
37		float* __restrict__ total_distances,
38		float* __restrict__ min_visibility,
39		const network_precision_t* __restrict__ params
40	) {
41		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
42		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
43	
44		bool valid = x < resolution.x && y < resolution.y;
45		uint32_t idx = x + resolution.x * y;
46	
47		SdfPayload& payload = payloads[idx];
48		Ray ray = {positions[idx], payload.dir};
49		ray.d = normalize(ray.d);
50	
51		bool alive = valid && ray.is_valid() && payload.alive && aabb.contains(ray.o);
52	
53		float total_dist = 0.0f;
54		float dist = 0.0f;
55		float prev_dist = 1e20f;
56		float min_vis = 1.0f;
57	
58		uint32_t n_steps = 0;
59	
60		while (true) {
61			dist = ((float)eval_sdf(ray.o, params)[0] - zero_offset) * distance_scale;
62	
63			// Implicit sync is fine here, because the following nerf model wants synchronized warps anyway
64			if (__all_sync(0xFFFFFFFF, !alive)) {
65				break;
66			}
67	
68			// All threads in the warp must execute the above MLPs for coherence reasons.
69			// Starting from here, it's fine to skip computation.
70			if (!alive) {
71				continue;
72			}
73	
74			ray.o = ray(dist);
75			++n_steps;
76	
77			// Skip over regions not covered by the octree
78			if (octree_nodes && !contains(octree_nodes, max_octree_depth, ray.o)) {
79				float octree_dist = ray_intersect(octree_nodes, max_octree_depth, ray.o, payload.dir) + 1e-6f;
80				dist += octree_dist;
81				ray.o = ray(octree_dist);
82			}
83	
84			// Collide with floor
85			if (ray.o.y < floor_y && ray.d.y < 0.f) {
86				float floor_dist = -(ray.o.y - floor_y) / ray.d.y;
87				dist += floor_dist;
88				ray.o = ray(floor_dist);
89	
90				alive = false;
91			}
92	
93			// Shadow ray per https://www.iquilezles.org/www/articles/rmshadows/rmshadows.htm
94			if (total_distances && dist > 0.0f) {
95				float y = dist * dist / (2.0f * prev_dist);
96				float d = sqrtf(dist * dist - y * y);
97	
98				min_vis = fminf(min_vis, k * d / fmaxf(0.0f, total_dist - y));
99				prev_dist = dist;
100				total_dist += dist;
101			}
102	
103			alive &= dist > maximum_distance && fabsf(dist / 2) > 3 * maximum_distance && aabb.contains(ray.o);
104		}
105	
106		if (!valid) {
107			return;
108		}
109	
110		positions[idx] = ray.o;
111		distances[idx] = dist;
112		payload.n_steps += n_steps;
113		payload.alive = false; // All payloads should have become inactive at this point!
114	
115		// Shadow ray
116		if (total_distances) {
117			prev_distances[idx] = prev_dist;
118			total_distances[idx] = total_dist;
119			min_visibility[idx] = min_vis;
120		}
121	}
