29	#include <tiny-cuda-nn/gpu_matrix.h>
30	#include <tiny-cuda-nn/network_with_input_encoding.h>
31	#include <tiny-cuda-nn/trainer.h>
32	
33	#include <cmrc/cmrc.hpp>
34	
35	CMRC_DECLARE(ngp);
36	
37	#ifdef copysign
38	#	undef copysign
39	#endif
40	
41	namespace ngp {
42	
43	static constexpr uint32_t MARCH_ITER = 10000;
44	
45	Testbed::NetworkDims Testbed::network_dims_sdf() const {
46		NetworkDims dims;
47		dims.n_input = 3;
48		dims.n_output = 1;
49		dims.n_pos = 3;
50		return dims;
51	}
52	
53	__device__ inline float square(float x) { return x * x; }
54	__device__ inline float mix(float a, float b, float t) { return a + (b - a) * t; }
55	__device__ inline vec3 mix(const vec3& a, const vec3& b, float t) { return a + (b - a) * t; }
56	
57	__device__ inline float SchlickFresnel(float u) {
58		float m = __saturatef(1.0 - u);
59		return square(square(m)) * m;
60	}
61	
62	__device__ inline float G1(float NdotH, float a) {
63		if (a >= 1.0) {
64			return 1.0 / PI();
65		}
66		float a2 = square(a);
67		float t = 1.0 + (a2 - 1.0) * NdotH * NdotH;
68		return (a2 - 1.0) / (PI() * log(a2) * t);
69	}
70	
71	__device__ inline float G2(float NdotH, float a) {
72		float a2 = square(a);
73		float t = 1.0 + (a2 - 1.0) * NdotH * NdotH;
74		return a2 / (PI() * t * t);
75	}
76	
77	__device__ inline float SmithG_GGX(float NdotV, float alphaG) {
78		float a = alphaG * alphaG;
79		float b = NdotV * NdotV;
80		return 1.0 / (NdotV + sqrtf(a + b - a * b));
81	}
82	
83	// this function largely based on:
84	// https://github.com/wdas/brdf/blob/master/src/brdfs/disney.brdf
85	// http://blog.selfshadow.com/publications/s2012-shading-course/burley/s2012_pbs_disney_brdf_notes_v3.pdf
86	__device__ vec3 evaluate_shading(
87		const vec3& base_color,
88		const vec3& ambient_color, // :)
89		const vec3& light_color,   // :)
90		float metallic,
91		float subsurface,
92		float specular,
93		float roughness,
94		float specular_tint,
95		float sheen,
96		float sheen_tint,
97		float clearcoat,
98		float clearcoat_gloss,
99		vec3 L,
100		vec3 V,
101		vec3 N
102	) {
103		float NdotL = dot(N, L);
104		float NdotV = dot(N, V);
105	
106		vec3 H = normalize(L + V);
107		float NdotH = dot(N, H);
108		float LdotH = dot(L, H);
109	
110		// Diffuse fresnel - go from 1 at normal incidence to .5 at grazing
111		// and mix in diffuse retro-reflection based on roughness
112		float FL = SchlickFresnel(NdotL), FV = SchlickFresnel(NdotV);
113		vec3 amb = (ambient_color * mix(0.2f, FV, metallic));
114		amb *= base_color;
115		if (NdotL < 0.f || NdotV < 0.f) {
116			return amb;
117		}
118	
119		float luminance = dot(base_color, vec3{0.3f, 0.6f, 0.1f});
120	
121		// normalize luminance to isolate hue and saturation components
122		vec3 Ctint = base_color * (1.f / (luminance + 0.00001f));
123		vec3 Cspec0 = mix(mix(vec3(1.0f), Ctint, specular_tint) * specular * 0.08f, base_color, metallic);
124		vec3 Csheen = mix(vec3(1.0f), Ctint, sheen_tint);
125	
126		float Fd90 = 0.5f + 2.0f * LdotH * LdotH * roughness;
127		float Fd = mix(1, Fd90, FL) * mix(1.f, Fd90, FV);
128	
129		// Based on Hanrahan-Krueger BRDF approximation of isotropic BSSRDF
130		// 1.25 scale is used to (roughly) preserve albedo
131		// Fss90 used to "flatten" retroreflection based on roughness
132		float Fss90 = LdotH * LdotH * roughness;
133		float Fss = mix(1.0f, Fss90, FL) * mix(1.0f, Fss90, FV);
134		float ss = 1.25f * (Fss * (1.f / (NdotL + NdotV) - 0.5f) + 0.5f);
135	
136		// Specular
137		float a = std::max(0.001f, square(roughness));
138		float Ds = G2(NdotH, a);
139		float FH = SchlickFresnel(LdotH);
140		vec3 Fs = mix(Cspec0, vec3(1.0f), FH);
141		float Gs = SmithG_GGX(NdotL, a) * SmithG_GGX(NdotV, a);
142	
143		// sheen
144		vec3 Fsheen = FH * sheen * Csheen;
145	
146		// clearcoat (ior = 1.5 -> F0 = 0.04)
147		float Dr = G1(NdotH, mix(0.1f, 0.001f, clearcoat_gloss));
148		float Fr = mix(0.04f, 1.0f, FH);
149		float Gr = SmithG_GGX(NdotL, 0.25f) * SmithG_GGX(NdotV, 0.25f);
150	
151		float CCs = 0.25f * clearcoat * Gr * Fr * Dr;
152		vec3 brdf = (float(1.0f / PI()) * mix(Fd, ss, subsurface) * base_color + Fsheen) * (1.0f - metallic) + Gs * Fs * Ds + vec3{CCs, CCs, CCs};
153		return vec3(brdf * light_color) * NdotL + amb;
154	}
155	
156	__global__ void advance_pos_kernel_sdf(
157		const uint32_t n_elements,
158		const float zero_offset,
159		vec3* __restrict__ positions,
160		float* __restrict__ distances,
161		SdfPayload* __restrict__ payloads,
162		BoundingBox aabb,
163		float floor_y,
164		const TriangleOctreeNode* __restrict__ octree_nodes,
165		int max_octree_depth,
166		float distance_scale,
167		float maximum_distance,
168		float k,
169		float* __restrict__ prev_distances,
170		float* __restrict__ total_distances,
171		float* __restrict__ min_visibility
172	) {
173		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
174		if (i >= n_elements) {
175			return;
176		}
177	
178		SdfPayload& payload = payloads[i];
179		if (!payload.alive) {
180			return;
181		}
182	
183		float distance = distances[i] - zero_offset;
184	
185		distance *= distance_scale;
186	
187		// Advance by the predicted distance
188		vec3 pos = positions[i];
189		pos += distance * payload.dir;
190	
191		// Skip over regions not covered by the octree
192		if (octree_nodes && !contains(octree_nodes, max_octree_depth, pos)) {
193			float octree_distance = ray_intersect(octree_nodes, max_octree_depth, pos, payload.dir) + 1e-6f;
194			distance += octree_distance;
195			pos += octree_distance * payload.dir;
196		}
197	
198		if (pos.y < floor_y && payload.dir.y < 0.f) {
199			float floor_dist = -(pos.y - floor_y) / payload.dir.y;
200			distance += floor_dist;
201			pos += floor_dist * payload.dir;
202			payload.alive = false;
203		}
204	
205		positions[i] = pos;
206	
207		if (total_distances && distance > 0.0f) {
208			// From https://www.iquilezles.org/www/articles/rmshadows/rmshadows.htm
209			float total_distance = total_distances[i];
210			float y = distance * distance / (2.0f * prev_distances[i]);
211			float d = sqrtf(distance * distance - y * y);
212	
213			min_visibility[i] = fminf(min_visibility[i], k * d / fmaxf(0.0f, total_distance - y));
214			prev_distances[i] = distance;
215			total_distances[i] = total_distance + distance;
216		}
217	
218		bool stay_alive = distance > maximum_distance && fabsf(distance / 2) > 3 * maximum_distance;
219		if (!stay_alive) {
220			payload.alive = false;
221			return;
222		}
223	
224		if (!aabb.contains(pos)) {
225			payload.alive = false;
226			return;
227		}
228	
229		++payload.n_steps;
230	}
