232	__global__ void perturb_sdf_samples(
233		uint32_t n_elements, const vec3* __restrict__ perturbations, vec3* __restrict__ positions, float* __restrict__ distances
234	) {
235		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
236		if (i >= n_elements) {
237			return;
238		}
239	
240		vec3 perturbation = perturbations[i];
241		positions[i] += perturbation;
242	
243		// Small epsilon above 1 to ensure a triangle is always found.
244		distances[i] = length(perturbation) * 1.001f;
245	}
