247	__global__ void prepare_shadow_rays(
248		const uint32_t n_elements,
249		vec3 sun_dir,
250		vec3* __restrict__ positions,
251		vec3* __restrict__ normals,
252		float* __restrict__ distances,
253		float* __restrict__ prev_distances,
254		float* __restrict__ total_distances,
255		float* __restrict__ min_visibility,
256		SdfPayload* __restrict__ payloads,
257		BoundingBox aabb,
258		const TriangleOctreeNode* __restrict__ octree_nodes,
259		int max_octree_depth
260	) {
261		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
262		if (i >= n_elements) {
263			return;
264		}
265	
266		SdfPayload& payload = payloads[i];
267	
268		// Step back a little along the ray to prevent self-intersection
269		vec3 view_pos = positions[i] + normalize(faceforward(normals[i], payload.dir, normals[i])) * 1e-3f;
270		vec3 dir = normalize(sun_dir);
271	
272		float t = fmaxf(aabb.ray_intersect(view_pos, dir).x + 1e-6f, 0.0f);
273		view_pos += t * dir;
274	
275		if (octree_nodes && !contains(octree_nodes, max_octree_depth, view_pos)) {
276			t = fmaxf(0.0f, ray_intersect(octree_nodes, max_octree_depth, view_pos, dir) + 1e-6f);
277			view_pos += t * dir;
278		}
279	
280		positions[i] = view_pos;
281	
282		if (!aabb.contains(view_pos)) {
283			distances[i] = MAX_DEPTH();
284			payload.alive = false;
285			min_visibility[i] = 1.0f;
286			return;
287		}
288	
289		distances[i] = MAX_DEPTH();
290		payload.idx = i;
291		payload.dir = dir;
292		payload.n_steps = 0;
293		payload.alive = true;
294	
295		if (prev_distances) {
296			prev_distances[i] = 1e20f;
297		}
298	
299		if (total_distances) {
300			total_distances[i] = 0.0f;
301		}
302	
303		if (min_visibility) {
304			min_visibility[i] = 1.0f;
305		}
306	}
