324	__global__ void shade_kernel_sdf(
325		const uint32_t n_elements,
326		BoundingBox aabb,
327		float floor_y,
328		const ERenderMode mode,
329		const BRDFParams brdf,
330		vec3 sun_dir,
331		vec3 up_dir,
332		mat4x3 camera_matrix,
333		vec3* __restrict__ positions,
334		vec3* __restrict__ normals,
335		float* __restrict__ distances,
336		SdfPayload* __restrict__ payloads,
337		vec4* __restrict__ frame_buffer,
338		float* __restrict__ depth_buffer
339	) {
340		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
341		if (i >= n_elements) {
342			return;
343		}
344	
345		SdfPayload& payload = payloads[i];
346		if (!aabb.contains(positions[i])) {
347			return;
348		}
349	
350		// The normal in memory isn't normalized yet
351		vec3 normal = normalize(normals[i]);
352		vec3 pos = positions[i];
353		bool floor = false;
354		if (pos.y < floor_y + 0.001f && payload.dir.y < 0.f) {
355			normal = vec3{0.0f, 1.0f, 0.0f};
356			floor = true;
357		}
358	
359		vec3 cam_pos = camera_matrix[3];
360		vec3 cam_fwd = camera_matrix[2];
361		float ao = powf(0.92f, payload.n_steps * 0.5f) * (1.f / 0.92f);
362		vec3 color;
363		switch (mode) {
364			case ERenderMode::AO: color = vec3(powf(0.92f, payload.n_steps)); break;
365			case ERenderMode::Shade: {
366				float skyam = -dot(normal, up_dir) * 0.5f + 0.5f;
367				vec3 suncol = vec3{255.f / 255.0f, 225.f / 255.0f, 195.f / 255.0f} * 4.f *
368					distances[i]; // Distance encodes shadow occlusion. 0=occluded, 1=no shadow
369				const vec3 skycol = vec3{195.f / 255.0f, 215.f / 255.0f, 255.f / 255.0f} * 4.f * skyam;
370				float check_size = 8.f / aabb.diag().x;
371				float check = ((int(floorf(check_size * (pos.x - aabb.min.x))) ^ int(floorf(check_size * (pos.z - aabb.min.z)))) & 1) ? 0.8f :
372																																		0.2f;
373				const vec3 floorcol = vec3{check * check * check, check * check, check};
374				color = evaluate_shading(
375					floor ? floorcol : brdf.basecolor * brdf.basecolor,
376					brdf.ambientcolor * skycol,
377					suncol,
378					floor ? 0.f : brdf.metallic,
379					floor ? 0.f : brdf.subsurface,
380					floor ? 1.f : brdf.specular,
381					floor ? 0.5f : brdf.roughness,
382					0.f,
383					floor ? 0.f : brdf.sheen,
384					0.f,
385					floor ? 0.f : brdf.clearcoat,
386					brdf.clearcoat_gloss,
387					sun_dir,
388					-normalize(payload.dir),
389					normal
390				);
391			} break;
392			case ERenderMode::Depth: color = vec3(dot(cam_fwd, pos - cam_pos)); break;
393			case ERenderMode::Positions: {
394				color = (pos - 0.5f) / 2.0f + 0.5f;
395			} break;
396			case ERenderMode::Normals: color = 0.5f * normal + 0.5f; break;
397			case ERenderMode::Cost: color = vec3((float)payload.n_steps / 30); break;
398			case ERenderMode::EncodingVis: color = normals[i]; break;
399		}
400	
401		frame_buffer[payload.idx] = {color.r, color.g, color.b, 1.0f};
402		depth_buffer[payload.idx] = dot(cam_fwd, pos - cam_pos);
403	}
