405	__global__ void compact_kernel_shadow_sdf(
406		const uint32_t n_elements,
407		const float zero_offset,
408		vec3* src_positions,
409		float* src_distances,
410		SdfPayload* src_payloads,
411		float* src_prev_distances,
412		float* src_total_distances,
413		float* src_min_visibility,
414		vec3* dst_positions,
415		float* dst_distances,
416		SdfPayload* dst_payloads,
417		float* dst_prev_distances,
418		float* dst_total_distances,
419		float* dst_min_visibility,
420		vec3* dst_final_positions,
421		float* dst_final_distances,
422		SdfPayload* dst_final_payloads,
423		float* dst_final_prev_distances,
424		float* dst_final_total_distances,
425		float* dst_final_min_visibility,
426		BoundingBox aabb,
427		uint32_t* counter,
428		uint32_t* finalCounter
429	) {
430		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
431		if (i >= n_elements) {
432			return;
433		}
434	
435		SdfPayload& src_payload = src_payloads[i];
436	
437		if (src_payload.alive) {
438			uint32_t idx = atomicAdd(counter, 1);
439			dst_payloads[idx] = src_payload;
440			dst_positions[idx] = src_positions[i];
441			dst_distances[idx] = src_distances[i];
442			dst_prev_distances[idx] = src_prev_distances[i];
443			dst_total_distances[idx] = src_total_distances[i];
444			dst_min_visibility[idx] = src_min_visibility[i];
445		} else { // For shadow rays, collect _all_ final samples to keep track of their partial visibility
446			uint32_t idx = atomicAdd(finalCounter, 1);
447			dst_final_payloads[idx] = src_payload;
448			dst_final_positions[idx] = src_positions[i];
449			dst_final_distances[idx] = src_distances[i];
450			dst_final_prev_distances[idx] = src_prev_distances[i];
451			dst_final_total_distances[idx] = src_total_distances[i];
452			dst_final_min_visibility[idx] = aabb.contains(src_positions[i]) ? 0.0f : src_min_visibility[i];
453		}
454	}
