456	__global__ void compact_kernel_sdf(
457		const uint32_t n_elements,
458		const float zero_offset,
459		vec3* src_positions,
460		float* src_distances,
461		SdfPayload* src_payloads,
462		vec3* dst_positions,
463		float* dst_distances,
464		SdfPayload* dst_payloads,
465		vec3* dst_final_positions,
466		float* dst_final_distances,
467		SdfPayload* dst_final_payloads,
468		BoundingBox aabb,
469		uint32_t* counter,
470		uint32_t* finalCounter
471	) {
472		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
473		if (i >= n_elements) {
474			return;
475		}
476	
477		SdfPayload& src_payload = src_payloads[i];
478	
479		if (src_payload.alive) {
480			uint32_t idx = atomicAdd(counter, 1);
481			dst_payloads[idx] = src_payload;
482			dst_positions[idx] = src_positions[i];
483			dst_distances[idx] = src_distances[i];
484		} else if (aabb.contains(src_positions[i])) {
