492	__global__ void uniform_octree_sample_kernel(
493		const uint32_t num_elements,
494		default_rng_t rng,
495		const TriangleOctreeNode* __restrict__ octree_nodes,
496		uint32_t num_nodes,
497		uint32_t depth,
498		vec3* __restrict__ samples
499	) {
500		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
501		if (i >= num_elements) {
502			return;
503		}
504	
505		rng.advance(i * (1 << 8));
506	
507		// Samples random nodes until a leaf is picked
508		uint32_t node;
509		uint32_t child;
510		do {
511			node = umin((uint32_t)(random_val(rng) * num_nodes), num_nodes - 1);
512			child = umin((uint32_t)(random_val(rng) * 8), 8u - 1);
513		} while (octree_nodes[node].depth < depth - 2 || octree_nodes[node].children[child] == -1);
514	
515		// Here it should be guaranteed that any child of the node is -1
516		float size = scalbnf(1.0f, -depth + 1);
517	
518		u16vec3 pos = octree_nodes[node].pos * uint16_t(2);
519		if (child & 1) {
520			++pos.x;
521		}
522		if (child & 2) {
523			++pos.y;
524		}
525		if (child & 4) {
526			++pos.z;
527		}
528		samples[i] = size * (vec3(pos) + samples[i]);
529	}
