531	__global__ void scale_to_aabb_kernel(uint32_t n_elements, BoundingBox aabb, vec3* __restrict__ inout) {
532		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
533		if (i >= n_elements) {
534			return;
535		}
536	
537		inout[i] = aabb.min + inout[i] * aabb.diag();
