540	__global__ void compare_signs_kernel(
541		uint32_t n_elements,
542		const vec3* positions,
543		const float* distances_ref,
544		const float* distances_model,
545		uint32_t* counters,
546		const TriangleOctreeNode* octree_nodes,
547		int max_octree_depth
548	) {
549		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
550		if (i >= n_elements) {
551			return;
552		}
553		bool inside1 = distances_ref[i] <= 0.f;
554		bool inside2 = distances_model[i] <= 0.f;
555		if (octree_nodes && !contains(octree_nodes, max_octree_depth, positions[i])) {
556			inside2 = inside1;          // assume, when using the octree, that the model is always correct outside the octree.
557			atomicAdd(&counters[6], 1); // outside the octree
558		} else {
559			atomicAdd(&counters[7], 1); // inside the octree
560		}
561		atomicAdd(&counters[inside1 ? 0 : 1], 1);
562		atomicAdd(&counters[inside2 ? 2 : 3], 1);
563		if (inside1 && inside2) {
564			atomicAdd(&counters[4], 1);
565		}
566		if (inside1 || inside2) {
567			atomicAdd(&counters[5], 1);
568		}
569	}
