589	__global__ void init_rays_with_payload_kernel_sdf(
590		uint32_t sample_index,
591		vec3* __restrict__ positions,
592		float* __restrict__ distances,
593		SdfPayload* __restrict__ payloads,
594		ivec2 resolution,
595		vec2 focal_length,
596		mat4x3 camera_matrix,
597		vec2 screen_center,
598		vec3 parallax_shift,
599		bool snap_to_pixel_centers,
600		BoundingBox aabb,
601		float floor_y,
602		float near_distance,
603		float plane_z,
604		float aperture_size,
605		Foveation foveation,
606		Buffer2DView<const vec4> envmap,
607		vec4* __restrict__ frame_buffer,
608		float* __restrict__ depth_buffer,
609		Buffer2DView<const uint8_t> hidden_area_mask,
610		Lens lens,
611		const TriangleOctreeNode* __restrict__ octree_nodes = nullptr,
612		int max_octree_depth = 0
613	) {
614		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
615		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
616	
617		if (x >= resolution.x || y >= resolution.y) {
618			return;
619		}
620	
621		uint32_t idx = x + resolution.x * y;
622	
623		if (plane_z < 0) {
624			aperture_size = 0.0;
625		}
626	
627		Ray ray = pixel_to_ray(
628			sample_index,
629			{(int)x, (int)y},
630			resolution,
631			focal_length,
632			camera_matrix,
633			screen_center,
634			parallax_shift,
635			snap_to_pixel_centers,
636			near_distance,
637			plane_z,
638			aperture_size,
639			foveation,
640			hidden_area_mask,
641			lens
642		);
643	
644		distances[idx] = MAX_DEPTH();
645		depth_buffer[idx] = MAX_DEPTH();
646	
647		SdfPayload& payload = payloads[idx];
648	
649		if (!ray.is_valid()) {
650			payload.dir = ray.d;
651			payload.idx = idx;
652			payload.n_steps = 0;
653			payload.alive = false;
654			positions[idx] = ray.o;
655			return;
656		}
657	
658		if (plane_z < 0) {
659			float n = length(ray.d);
660			payload.dir = (1.0f / n) * ray.d;
661			payload.idx = idx;
662			payload.n_steps = 0;
663			payload.alive = false;
664			positions[idx] = ray.o - plane_z * ray.d;
665			depth_buffer[idx] = -plane_z;
666			return;
667		}
668	
669		ray.d = normalize(ray.d);
670		float t = max(aabb.ray_intersect(ray.o, ray.d).x, 0.0f);
671	
672		ray.advance(t + 1e-6f);
673	
674		if (octree_nodes && !contains(octree_nodes, max_octree_depth, ray.o)) {
675			t = max(0.0f, ray_intersect(octree_nodes, max_octree_depth, ray.o, ray.d));
676			if (ray.o.y > floor_y && ray.d.y < 0.f) {
677				float floor_dist = -(ray.o.y - floor_y) / ray.d.y;
678				if (floor_dist > 0.f) {
679					t = min(t, floor_dist);
680				}
681			}
682	
683			ray.advance(t + 1e-6f);
684		}
685	
686		positions[idx] = ray.o;
687	
688		if (envmap) {
689			frame_buffer[idx] = read_envmap(envmap, ray.d);
690		}
691	
692		payload.dir = ray.d;
693		payload.idx = idx;
694		payload.n_steps = 0;
695		payload.alive = aabb.contains(ray.o);
696	}
