716	void Testbed::SphereTracer::init_rays_from_camera(
717		uint32_t sample_index,
718		const ivec2& resolution,
719		const vec2& focal_length,
720		const mat4x3& camera_matrix,
721		const vec2& screen_center,
722		const vec3& parallax_shift,
723		bool snap_to_pixel_centers,
724		const BoundingBox& aabb,
725		float floor_y,
726		float near_distance,
727		float plane_z,
728		float aperture_size,
729		const Foveation& foveation,
730		const Buffer2DView<const vec4>& envmap,
731		vec4* frame_buffer,
732		float* depth_buffer,
733		const Buffer2DView<const uint8_t>& hidden_area_mask,
734		const Lens& lens,
735		const TriangleOctree* octree,
736		uint32_t n_octree_levels,
737		cudaStream_t stream
738	) {
739		// Make sure we have enough memory reserved to render at the requested resolution
740		size_t n_pixels = (size_t)resolution.x * resolution.y;
741		enlarge(n_pixels, stream);
742	
743		const dim3 threads = {16, 8, 1};
