746			sample_index,
747			m_rays[0].pos,
748			m_rays[0].distance,
749			m_rays[0].payload,
750			resolution,
751			focal_length,
752			camera_matrix,
753			screen_center,
754			parallax_shift,
755			snap_to_pixel_centers,
756			aabb,
757			floor_y,
758			near_distance,
759			plane_z,
760			aperture_size,
761			foveation,
762			envmap,
763			frame_buffer,
764			depth_buffer,
