798	uint32_t Testbed::SphereTracer::trace(
799		const distance_fun_t& distance_function,
800		const Network<float, network_precision_t>* network,
801		float zero_offset,
802		float distance_scale,
803		float maximum_distance,
804		const BoundingBox& aabb,
805		const float floor_y,
806		const TriangleOctree* octree,
807		const uint32_t n_octree_levels,
808		cudaStream_t stream
809	) {
810		if (m_n_rays_initialized == 0) {
811			return 0;
812		}
813	
814		CUDA_CHECK_THROW(cudaMemsetAsync(m_hit_counter, 0, sizeof(uint32_t), stream));
815	
816		const uint32_t STEPS_INBETWEEN_COMPACTION = 4;
817	
818		uint32_t n_alive = m_n_rays_initialized;
819		m_n_rays_initialized = 0;
820	
821		uint32_t i = 1;
822		uint32_t double_buffer_index = 0;
823		while (i < MARCH_ITER) {
824			// Compact more frequently in the first couple of steps
825			uint32_t step_size = std::min(i, STEPS_INBETWEEN_COMPACTION);
826	
827			RaysSdfSoa& rays_current = m_rays[(double_buffer_index + 1) % 2];
828			RaysSdfSoa& rays_tmp = m_rays[double_buffer_index % 2];
829			++double_buffer_index;
830	
831			if (m_fused_trace_kernel) {
832				dim3 threads, blocks;
833				if (m_resolution.x >= 8 && m_resolution.y >= 16) {
834					threads = {8, 16, 1};
835					blocks = {
836						div_round_up((uint32_t)m_resolution.x, threads.x), div_round_up((uint32_t)m_resolution.y, threads.y), 1
837					};
838				} else {
839					threads = {N_THREADS_LINEAR, 1, 1};
840					blocks = {n_blocks_linear(n_alive, threads.x), 1, 1};
841				}
842	
843				m_fused_trace_kernel->launch(
844					blocks,
845					threads,
846					0,
847					stream,
848					m_resolution,
849					zero_offset,
850					rays_tmp.pos,
851					rays_tmp.distance,
852					rays_tmp.payload,
853					aabb,
854					floor_y,
855					octree ? octree->nodes_gpu() : nullptr,
856					octree ? n_octree_levels : 0,
857					distance_scale,
858					maximum_distance,
859					m_shadow_sharpness,
860					m_trace_shadow_rays ? rays_tmp.prev_distance : nullptr,
861					m_trace_shadow_rays ? rays_tmp.total_distance : nullptr,
862					m_trace_shadow_rays ? rays_tmp.min_visibility : nullptr,
863					network->inference_params()
864				);
865			}
866	
867			// Compact rays that did not diverge yet
868			{
869				CUDA_CHECK_THROW(cudaMemsetAsync(m_alive_counter, 0, sizeof(uint32_t), stream));
870				if (m_trace_shadow_rays) {
871					linear_kernel(
872						compact_kernel_shadow_sdf,
873						0,
874						stream,
875						n_alive,
876						zero_offset,
877						rays_tmp.pos,
878						rays_tmp.distance,
879						rays_tmp.payload,
880						rays_tmp.prev_distance,
881						rays_tmp.total_distance,
882						rays_tmp.min_visibility,
883						rays_current.pos,
884						rays_current.distance,
885						rays_current.payload,
886						rays_current.prev_distance,
887						rays_current.total_distance,
888						rays_current.min_visibility,
889						m_rays_hit.pos,
890						m_rays_hit.distance,
891						m_rays_hit.payload,
892						m_rays_hit.prev_distance,
893						m_rays_hit.total_distance,
894						m_rays_hit.min_visibility,
895						aabb,
896						m_alive_counter,
897						m_hit_counter
898					);
899				} else {
900					linear_kernel(
901						compact_kernel_sdf,
902						0,
903						stream,
904						n_alive,
905						zero_offset,
906						rays_tmp.pos,
907						rays_tmp.distance,
908						rays_tmp.payload,
909						rays_current.pos,
910						rays_current.distance,
911						rays_current.payload,
912						m_rays_hit.pos,
913						m_rays_hit.distance,
914						m_rays_hit.payload,
915						aabb,
916						m_alive_counter,
917						m_hit_counter
918					);
919				}
920				CUDA_CHECK_THROW(cudaMemcpyAsync(&n_alive, m_alive_counter, sizeof(uint32_t), cudaMemcpyDeviceToHost, stream));
921				CUDA_CHECK_THROW(cudaStreamSynchronize(stream));
922			}
923	
924			if (n_alive == 0) {
925				break;
926			}
927	
928			for (uint32_t j = 0; j < step_size; ++j) {
929				distance_function(n_alive, rays_current.pos, rays_current.distance, stream);
930				linear_kernel(
931					advance_pos_kernel_sdf,
932					0,
933					stream,
934					n_alive,
935					zero_offset,
936					rays_current.pos,
937					rays_current.distance,
938					rays_current.payload,
939					aabb,
940					floor_y,
941					octree ? octree->nodes_gpu() : nullptr,
942					octree ? n_octree_levels : 0,
943					distance_scale,
944					maximum_distance,
945					m_shadow_sharpness,
946					m_trace_shadow_rays ? rays_current.prev_distance : nullptr,
947					m_trace_shadow_rays ? rays_current.total_distance : nullptr,
948					m_trace_shadow_rays ? rays_current.min_visibility : nullptr
949				);
950			}
951	
952			i += step_size;
953		}
954	
955		uint32_t n_hit;
956		CUDA_CHECK_THROW(cudaMemcpyAsync(&n_hit, m_hit_counter, sizeof(uint32_t), cudaMemcpyDeviceToHost, stream));
957		CUDA_CHECK_THROW(cudaStreamSynchronize(stream));
958		return n_hit;
959	}
