1047	void Testbed::FiniteDifferenceNormalsApproximator::enlarge(uint32_t n_elements, cudaStream_t stream) {
1048		n_elements = next_multiple(n_elements, BATCH_SIZE_GRANULARITY);
1049		auto scratch = allocate_workspace_and_distribute<vec3, vec3, vec3, float, float, float, float, float, float>(
1050			stream, &m_scratch_alloc, n_elements, n_elements, n_elements, n_elements, n_elements, n_elements, n_elements, n_elements, n_elements
1051		);
1052	
1053		dx = std::get<0>(scratch);
1054		dy = std::get<1>(scratch);
1055		dz = std::get<2>(scratch);
1056	
1057		dist_dx_pos = std::get<3>(scratch);
1058		dist_dy_pos = std::get<4>(scratch);
1059		dist_dz_pos = std::get<5>(scratch);
1060	
1061		dist_dx_neg = std::get<6>(scratch);
1062		dist_dy_neg = std::get<7>(scratch);
1063		dist_dz_neg = std::get<8>(scratch);
