1066	void Testbed::FiniteDifferenceNormalsApproximator::normal(
1067		uint32_t n_elements, const distance_fun_t& distance_function, const vec3* pos, vec3* normal, float epsilon, cudaStream_t stream
1068	) {
1069		enlarge(n_elements, stream);
1070	
1071		parallel_for_gpu(stream, n_elements, [pos = pos, dx = dx, dy = dy, dz = dz, epsilon] __device__(size_t i) {
1072			vec3 p = pos[i];
1073			dx[i] = vec3{p.x + epsilon, p.y, p.z};
1074			dy[i] = vec3{p.x, p.y + epsilon, p.z};
1075			dz[i] = vec3{p.x, p.y, p.z + epsilon};
1076		});
1077	
1078		distance_function(n_elements, dx, dist_dx_pos, stream);
1079		distance_function(n_elements, dy, dist_dy_pos, stream);
1080		distance_function(n_elements, dz, dist_dz_pos, stream);
1081	
1082		parallel_for_gpu(stream, n_elements, [pos = pos, dx = dx, dy = dy, dz = dz, epsilon] __device__(size_t i) {
1083			vec3 p = pos[i];
1084			dx[i] = vec3{p.x - epsilon, p.y, p.z};
1085			dy[i] = vec3{p.x, p.y - epsilon, p.z};
1086			dz[i] = vec3{p.x, p.y, p.z - epsilon};
1087		});
1088	
1089		distance_function(n_elements, dx, dist_dx_neg, stream);
1090		distance_function(n_elements, dy, dist_dy_neg, stream);
1091		distance_function(n_elements, dz, dist_dz_neg, stream);
1092	
1093		parallel_for_gpu(
1094			stream,
1095			n_elements,
1096			[normal = normal,
1097			 dist_dx_pos = dist_dx_pos,
1098			 dist_dx_neg = dist_dx_neg,
1099			 dist_dy_pos = dist_dy_pos,
1100			 dist_dy_neg = dist_dy_neg,
1101			 dist_dz_pos = dist_dz_pos,
1102			 dist_dz_neg = dist_dz_neg] __device__(size_t i) {
1103				normal[i] = {dist_dx_pos[i] - dist_dx_neg[i], dist_dy_pos[i] - dist_dy_neg[i], dist_dz_pos[i] - dist_dz_neg[i]};
1104			}
1105		);
1106	}
