1108	void Testbed::render_sdf(
1109		cudaStream_t stream,
1110		CudaDevice& device,
1111		const distance_fun_t& distance_function,
1112		const normals_fun_t& normals_function,
1113		const CudaRenderBufferView& render_buffer,
1114		const vec2& focal_length,
1115		const mat4x3& camera_matrix,
1116		const vec2& screen_center,
1117		const Foveation& foveation,
1118		const Lens& lens,
1119		int visualized_dimension
1120	) {
1121		auto jit_guard = m_network->jit_guard(stream, true);
1122	
1123		float plane_z = m_slice_plane_z + m_scale;
1124		if (m_render_mode == ERenderMode::Slice) {
1125			plane_z = -plane_z;
1126		}
1127		auto* octree_ptr = m_sdf.uses_takikawa_encoding || m_sdf.use_triangle_octree ? m_sdf.triangle_octree.get() : nullptr;
1128	
1129		SphereTracer tracer;
1130	
1131		uint32_t n_octree_levels = octree_ptr ? octree_ptr->depth() : 0;
1132	
1133		BoundingBox sdf_bounding_box = m_aabb;
1134		sdf_bounding_box.inflate(m_sdf.zero_offset);
1135	
1136		if (m_jit_fusion) {
1137			if (!device.fused_render_kernel()) {
1138				try {
1139					device.set_fused_render_kernel(std::make_unique<CudaRtcKernel>(
1140						"trace_sdf",
1141						fmt::format(
1142							"{}\n#include <neural-graphics-primitives/fused_kernels/trace_sdf.cuh>\n",
1143							m_network->generate_device_function("eval_sdf")
1144						),
1145						all_files(cmrc::ngp::get_filesystem())
1146					));
1147				} catch (const std::runtime_error& e) {
1148					tlog::warning() << e.what();
1149					tlog::warning() << "Disabling JIT fusion.";
1150					m_jit_fusion = false;
1151				}
1152			}
1153	
1154			if (device.fused_render_kernel()) {
1155				tracer.set_fused_trace_kernel(device.fused_render_kernel());
1156			}
1157		}
1158	
1159		tracer.init_rays_from_camera(
1160			render_buffer.spp,
1161			render_buffer.resolution,
1162			focal_length,
1163			camera_matrix,
1164			screen_center,
1165			m_parallax_shift,
1166			m_snap_to_pixel_centers,
1167			sdf_bounding_box,
1168			get_floor_y(),
1169			m_render_near_distance,
1170			plane_z,
1171			m_aperture_size,
1172			foveation,
1173			m_envmap.inference_view(),
1174			render_buffer.frame_buffer,
1175			render_buffer.depth_buffer,
1176			render_buffer.hidden_area_mask ? render_buffer.hidden_area_mask->const_view() : Buffer2DView<const uint8_t>{},
1177			lens,
1178			octree_ptr,
1179			n_octree_levels,
1180			stream
1181		);
1182	
1183		bool gt_raytrace = m_render_ground_truth && m_sdf.groundtruth_mode == ESDFGroundTruthMode::RaytracedMesh;
1184	
1185		auto trace = [&](SphereTracer& tracer) {
1186			if (gt_raytrace) {
1187				return tracer.trace_bvh(m_sdf.triangle_bvh.get(), m_sdf.triangles_gpu.data(), stream);
1188			} else {
1189				return tracer.trace(
1190					distance_function,
1191					m_network.get(),
1192					m_sdf.zero_offset,
1193					m_sdf.distance_scale,
1194					m_sdf.maximum_distance,
1195					sdf_bounding_box,
1196					get_floor_y(),
1197					octree_ptr,
1198					n_octree_levels,
1199					stream
1200				);
1201			}
1202		};
1203	
1204		uint32_t n_hit;
1205		if (m_render_mode == ERenderMode::Slice) {
1206			n_hit = tracer.n_rays_initialized();
1207		} else {
1208			n_hit = trace(tracer);
1209		}
1210	
1211		RaysSdfSoa& rays_hit = m_render_mode == ERenderMode::Slice || gt_raytrace ? tracer.rays_init() : tracer.rays_hit();
1212	
1213		if (m_render_mode == ERenderMode::Slice) {
1214			if (visualized_dimension == -1) {
1215				distance_function(n_hit, rays_hit.pos, rays_hit.distance, stream);
1216				extract_dimension_pos_neg_kernel<float><<<n_blocks_linear(n_hit * 3), N_THREADS_LINEAR, 0, stream>>>(
1217					n_hit * 3, 0, 1, 3, rays_hit.distance, CM, (float*)rays_hit.normal
1218				);
1219			} else {
1220				// Store colors in the normal buffer
1221				uint32_t n_elements = next_multiple(n_hit, BATCH_SIZE_GRANULARITY);
1222	
1223				GPUMatrix<float> positions_matrix((float*)rays_hit.pos, 3, n_elements);
1224				GPUMatrix<float> colors_matrix((float*)rays_hit.normal, 3, n_elements);
1225				m_network->visualize_activation(stream, m_visualized_layer, visualized_dimension, positions_matrix, colors_matrix);
1226			}
1227		}
1228	
1229		ERenderMode render_mode = (visualized_dimension > -1 || m_render_mode == ERenderMode::Slice) ? ERenderMode::EncodingVis : m_render_mode;
1230		if (render_mode == ERenderMode::Shade || render_mode == ERenderMode::Normals) {
1231			if (m_sdf.analytic_normals || gt_raytrace) {
1232				normals_function(n_hit, rays_hit.pos, rays_hit.normal, stream);
1233			} else {
1234				float fd_normals_epsilon = m_sdf.fd_normals_epsilon;
1235	
1236				FiniteDifferenceNormalsApproximator fd_normals;
1237				fd_normals.normal(n_hit, distance_function, rays_hit.pos, rays_hit.normal, fd_normals_epsilon, stream);
1238			}
1239	
1240			if (render_mode == ERenderMode::Shade && n_hit > 0) {
1241				// Shadow rays towards the sun
1242				SphereTracer shadow_tracer;
1243	
1244				shadow_tracer.init_rays_from_data(n_hit, rays_hit, stream);
1245				shadow_tracer.set_fused_trace_kernel(tracer.fused_trace_kernel());
1246				shadow_tracer.set_trace_shadow_rays(true);
1247				shadow_tracer.set_shadow_sharpness(m_sdf.shadow_sharpness);
1248				RaysSdfSoa& shadow_rays_init = shadow_tracer.rays_init();
1249				linear_kernel(
1250					prepare_shadow_rays,
1251					0,
1252					stream,
1253					n_hit,
1254					normalize(m_sun_dir),
1255					shadow_rays_init.pos,
1256					shadow_rays_init.normal,
1257					shadow_rays_init.distance,
1258					shadow_rays_init.prev_distance,
1259					shadow_rays_init.total_distance,
1260					shadow_rays_init.min_visibility,
1261					shadow_rays_init.payload,
1262					sdf_bounding_box,
1263					octree_ptr ? octree_ptr->nodes_gpu() : nullptr,
1264					n_octree_levels
1265				);
1266	
1267				uint32_t n_hit_shadow = trace(shadow_tracer);
1268				auto& shadow_rays_hit = gt_raytrace ? shadow_tracer.rays_init() : shadow_tracer.rays_hit();
1269	
1270				linear_kernel(
1271					write_shadow_ray_result,
1272					0,
1273					stream,
1274					n_hit_shadow,
1275					sdf_bounding_box,
1276					shadow_rays_hit.pos,
1277					shadow_rays_hit.payload,
1278					shadow_rays_hit.min_visibility,
1279					rays_hit.distance
1280				);
1281	
1282				// todo: Reflection rays?
1283			}
1284		} else if (render_mode == ERenderMode::EncodingVis && m_render_mode != ERenderMode::Slice) {
1285			// HACK: Store colors temporarily in the normal buffer
1286			uint32_t n_elements = next_multiple(n_hit, BATCH_SIZE_GRANULARITY);
1287	
1288			GPUMatrix<float> positions_matrix((float*)rays_hit.pos, 3, n_elements);
1289			GPUMatrix<float> colors_matrix((float*)rays_hit.normal, 3, n_elements);
1290			m_network->visualize_activation(stream, m_visualized_layer, visualized_dimension, positions_matrix, colors_matrix);
1291		}
1292	
1293		linear_kernel(
1294			shade_kernel_sdf,
1295			0,
1296			stream,
1297			n_hit,
1298			m_aabb,
1299			get_floor_y(),
1300			render_mode,
1301			m_sdf.brdf,
1302			normalize(m_sun_dir),
1303			normalize(m_up_dir),
1304			camera_matrix,
1305			rays_hit.pos,
1306			rays_hit.normal,
1307			rays_hit.distance,
1308			rays_hit.payload,
1309			render_buffer.frame_buffer,
1310			render_buffer.depth_buffer
1311		);
1312	
1313		if (render_mode == ERenderMode::Cost) {
1314			std::vector<SdfPayload> payloads_final_cpu(n_hit);
1315			CUDA_CHECK_THROW(
1316				cudaMemcpyAsync(payloads_final_cpu.data(), rays_hit.payload, n_hit * sizeof(SdfPayload), cudaMemcpyDeviceToHost, stream)
1317			);
1318			CUDA_CHECK_THROW(cudaStreamSynchronize(stream));
1319			size_t total_n_steps = 0;
1320			for (uint32_t i = 0; i < n_hit; ++i) {
1321				total_n_steps += payloads_final_cpu[i].n_steps;
1322			}
1323	
1324			tlog::info() << "Total steps per hit= " << total_n_steps << "/" << n_hit << " = " << ((float)total_n_steps / (float)n_hit);
1325		}
1326	}
1327	
1328	std::vector<vec3> load_stl(const fs::path& path) {
1329		std::vector<vec3> vertices;
1330	
1331		std::ifstream f{native_string(path), std::ios::in | std::ios::binary};
1332		if (!f) {
1333			throw std::runtime_error{fmt::format("Mesh file '{}' not found", path.str())};
1334		}
1335	
1336		uint32_t buf[21] = {};
1337		f.read((char*)buf, 4 * 21);
1338		if (f.gcount() < 4 * 21) {
1339			throw std::runtime_error{fmt::format("Mesh file '{}' too small for STL header", path.str())};
1340		}
1341	
1342		uint32_t nfaces = buf[20];
1343		if (memcmp(buf, "solid", 5) == 0 || buf[20] == 0) {
1344			throw std::runtime_error{fmt::format("ASCII STL file '{}' not supported", path.str())};
1345		}
1346	
1347		vertices.reserve(nfaces * 3);
1348		for (uint32_t i = 0; i < nfaces; ++i) {
1349			f.read((char*)buf, 50);
1350			if (f.gcount() < 50) {
1351				nfaces = i;
1352				break;
1353			}
1354	
1355			vertices.push_back(*(vec3*)(buf + 3));
1356			vertices.push_back(*(vec3*)(buf + 6));
1357			vertices.push_back(*(vec3*)(buf + 9));
1358		}
1359	
1360		return vertices;
1361	}
1362	
1363	void Testbed::load_mesh(const fs::path& data_path) {
1364		tlog::info() << "Loading mesh from '" << data_path << "'";
1365		auto start = std::chrono::steady_clock::now();
1366	
1367		std::vector<vec3> vertices;
1368		if (equals_case_insensitive(data_path.extension(), "obj")) {
1369			vertices = load_obj(data_path.str());
1370		} else if (equals_case_insensitive(data_path.extension(), "stl")) {
1371			vertices = load_stl(data_path.str());
1372		} else {
1373			throw std::runtime_error{"SDF data path must be a mesh in ascii .obj or binary .stl format."};
1374		}
1375	
1376		// The expected format is
1377		// [v1.x][v1.y][v1.z][v2.x]...
1378		size_t n_vertices = vertices.size();
1379		size_t n_triangles = n_vertices / 3;
1380	
1381		m_raw_aabb.min = vec3(std::numeric_limits<float>::infinity());
1382		m_raw_aabb.max = vec3(-std::numeric_limits<float>::infinity());
1383		for (size_t i = 0; i < n_vertices; ++i) {
1384			m_raw_aabb.enlarge(vertices[i]);
1385		}
1386	
1387		// Inflate AABB by 1% to give the network a little wiggle room.
1388		const float inflation = 0.005f;
1389	
1390		m_raw_aabb.inflate(length(m_raw_aabb.diag()) * inflation);
1391		m_sdf.mesh_scale = max(m_raw_aabb.diag());
1392	
1393		// Normalize vertex coordinates to lie within [0,1]^3.
1394		// This way, none of the constants need to carry around
1395		// bounding box factors.
1396		for (size_t i = 0; i < n_vertices; ++i) {
1397			vertices[i] = (vertices[i] - m_raw_aabb.min - 0.5f * m_raw_aabb.diag()) / m_sdf.mesh_scale + 0.5f;
1398		}
1399	
1400		m_aabb = {};
1401		for (size_t i = 0; i < n_vertices; ++i) {
1402			m_aabb.enlarge(vertices[i]);
1403		}
1404	
1405		m_aabb.inflate(length(m_aabb.diag()) * inflation);
1406		m_aabb = m_aabb.intersection(BoundingBox{vec3(0.0f), vec3(1.0f)});
1407		m_render_aabb = m_aabb;
1408		m_render_aabb_to_local = mat3::identity();
1409		m_mesh.thresh = 0.f;
1410	
1411		m_sdf.triangles_cpu.resize(n_triangles);
1412		for (size_t i = 0; i < n_vertices; i += 3) {
1413			m_sdf.triangles_cpu[i / 3] = {vertices[i + 0], vertices[i + 1], vertices[i + 2]};
1414		}
1415	
1416		if (!m_sdf.triangle_bvh) {
1417			m_sdf.triangle_bvh = TriangleBvh::make();
1418		}
1419	
1420		m_sdf.triangle_bvh->build(m_sdf.triangles_cpu, 8);
1421		m_sdf.triangles_gpu.resize_and_copy_from_host(m_sdf.triangles_cpu);
1422		m_sdf.triangle_bvh->build_optix(m_sdf.triangles_gpu, m_stream.get());
1423	
1424		m_sdf.triangle_octree.reset(new TriangleOctree{});
1425		m_sdf.triangle_octree->build(*m_sdf.triangle_bvh, m_sdf.triangles_cpu, 10);
1426	
1427		m_bounding_radius = length(vec3(0.5f));
1428	
1429		// Compute discrete probability distribution for later sampling of the mesh's surface
1430		m_sdf.triangle_weights.resize(n_triangles);
1431		for (size_t i = 0; i < n_triangles; ++i) {
1432			m_sdf.triangle_weights[i] = m_sdf.triangles_cpu[i].surface_area();
1433		}
1434		m_sdf.triangle_distribution.build(m_sdf.triangle_weights);
1435	
1436		// Move CDF to gpu
1437		m_sdf.triangle_cdf.resize_and_copy_from_host(m_sdf.triangle_distribution.cdf);
1438	
1439		// Clear training data as it's no longer representative
1440		// of the previously loaded mesh... but don't clear the network.
1441		// Perhaps it'll look interesting while morphing from one mesh to another.
1442		m_sdf.training.idx = 0;
1443		m_sdf.training.size = 0;
1444	
1445		tlog::success() << "Loaded mesh after " << tlog::durationToString(std::chrono::steady_clock::now() - start);
1446		tlog::info() << "  n_triangles=" << n_triangles << " aabb=" << m_raw_aabb;
1447	}
1448	
1449	void Testbed::generate_training_samples_sdf(vec3* positions, float* distances, uint32_t n_to_generate, cudaStream_t stream, bool uniform_only) {
1450		uint32_t n_to_generate_base = n_to_generate / 8;
1451		const uint32_t n_to_generate_surface_exact = uniform_only ? 0 : n_to_generate_base * 4;
1452		const uint32_t n_to_generate_surface_offset = uniform_only ? 0 : n_to_generate_base * 3;
1453		const uint32_t n_to_generate_uniform = uniform_only ? n_to_generate : n_to_generate_base * 1;
1454	
1455		const uint32_t n_to_generate_surface = n_to_generate_surface_exact + n_to_generate_surface_offset;
1456	
1457		// Generate uniform 3D samples. Some of these will be transformed to cover the surfaces uniformly. Others will be left as-is.
1458		generate_random_uniform<float>(stream, m_rng, n_to_generate * 3, (float*)positions);
1459	
1460		linear_kernel(
1461			sample_uniform_on_triangle_kernel,
1462			0,
1463			stream,
1464			n_to_generate_surface,
1465			m_sdf.triangle_cdf.data(),
1466			(uint32_t)m_sdf.triangle_cdf.size(),
1467			m_sdf.triangles_gpu.data(),
1468			positions
1469		);
1470	
1471		// The distances of points on the mesh are zero. Can immediately set.
1472		CUDA_CHECK_THROW(cudaMemsetAsync(distances, 0, n_to_generate_surface_exact * sizeof(float), stream));
1473	
1474		// If we have an octree, generate uniform samples within that octree.
1475		// Otherwise, at least confine uniform samples to the AABB.
1476		// (For the uniform_only case, we always use the AABB, then the IoU kernel checks against the octree later)
1477		float stddev = m_bounding_radius / 1024.0f * m_sdf.training.surface_offset_scale;
1478		if (!uniform_only && (m_sdf.uses_takikawa_encoding || m_sdf.use_triangle_octree)) {
1479			linear_kernel(
1480				uniform_octree_sample_kernel,
1481				0,
1482				stream,
1483				n_to_generate_uniform,
1484				m_rng,
1485				m_sdf.triangle_octree->nodes_gpu(),
1486				m_sdf.triangle_octree->n_nodes(),
1487				m_sdf.triangle_octree->depth(),
1488				positions + n_to_generate_surface
1489			);
1490			m_rng.advance();
1491	
1492			// If we know the finest discretization of the octree, we can concentrate
1493			// points MUCH closer to the mesh surface
1494			float leaf_size = scalbnf(1.0f, -m_sdf.triangle_octree->depth() + 1);
1495			if (leaf_size < stddev) {
1496				tlog::warning() << "leaf_size < stddev";
1497				stddev = leaf_size;
1498			}
1499	
1500			linear_kernel(assign_float, 0, stream, n_to_generate_uniform, length(vec3(leaf_size)) * 1.001f, distances + n_to_generate_surface);
1501		} else {
1502			BoundingBox sdf_aabb = m_aabb;
1503			sdf_aabb.inflate(m_sdf.zero_offset);
1504			linear_kernel(scale_to_aabb_kernel, 0, stream, n_to_generate_uniform, sdf_aabb, positions + n_to_generate_surface);
1505	
1506			linear_kernel(assign_float, 0, stream, n_to_generate_uniform, length(sdf_aabb.diag()) * 1.001f, distances + n_to_generate_surface);
1507		}
1508	
1509		m_sdf.training.perturbations.enlarge(n_to_generate_surface_offset);
1510		generate_random_logistic<float>(stream, m_rng, n_to_generate_surface_offset * 3, (float*)m_sdf.training.perturbations.data(), 0.0f, stddev);
1511	
1512		linear_kernel(
1513			perturb_sdf_samples,
1514			0,
1515			stream,
1516			n_to_generate_surface_offset,
1517			m_sdf.training.perturbations.data(),
1518			positions + n_to_generate_surface_exact,
1519			distances + n_to_generate_surface_exact
1520		);
1521	
1522		// The following function expects `distances` to contain an upper bound on the
1523		// true distance. This accelerates lookups.
1524		m_sdf.triangle_bvh->signed_distance_gpu(
1525			n_to_generate_uniform + n_to_generate_surface_offset,
1526			m_sdf.mesh_sdf_mode,
1527			positions + n_to_generate_surface_exact,
1528			distances + n_to_generate_surface_exact,
1529			m_sdf.triangles_gpu.data(),
1530			true,
1531			stream
1532		);
1533	
1534		CUDA_CHECK_THROW(cudaStreamSynchronize(stream));
1535	}
1536	
1537	__global__ void generate_grid_samples_sdf_uniform(ivec3 res_3d, BoundingBox aabb, const mat3& render_aabb_to_local, vec3* __restrict__ out) {
1538		uint32_t x = threadIdx.x + blockIdx.x * blockDim.x;
1539		uint32_t y = threadIdx.y + blockIdx.y * blockDim.y;
1540		uint32_t z = threadIdx.z + blockIdx.z * blockDim.z;
1541		if (x >= res_3d.x || y >= res_3d.y || z >= res_3d.z) {
1542			return;
1543		}
1544		uint32_t i = x + y * res_3d.x + z * res_3d.x * res_3d.y;
1545		vec3 pos = vec3{(float)x, (float)y, (float)z} * vec3{1.f / res_3d.x, 1.f / res_3d.y, 1.f / res_3d.z};
1546		pos = pos * (aabb.max - aabb.min) + aabb.min;
1547		out[i] = transpose(render_aabb_to_local) * pos;
1548	}
1549	
1550	GPUMemory<float> Testbed::get_sdf_gt_on_grid(ivec3 res3d, const BoundingBox& aabb, const mat3& render_aabb_to_local) {
1551		const uint32_t n_elements = (res3d.x * res3d.y * res3d.z);
1552		GPUMemory<float> density(n_elements);
1553		GPUMemoryArena::Allocation alloc;
1554		auto scratch = allocate_workspace_and_distribute<vec3>(m_stream.get(), &alloc, n_elements);
1555		vec3* positions = std::get<0>(scratch);
1556		float* sdf_out = density.data();
1557		const dim3 threads = {16, 8, 1};
1558		const dim3 blocks = {
1559			div_round_up((uint32_t)res3d.x, threads.x), div_round_up((uint32_t)res3d.y, threads.y), div_round_up((uint32_t)res3d.z, threads.z)
1560		};
1561		generate_grid_samples_sdf_uniform<<<blocks, threads, 0, m_stream.get()>>>(res3d, aabb, render_aabb_to_local, positions);
1562		CUDA_CHECK_THROW(cudaStreamSynchronize(m_stream.get()));
1563		m_sdf.triangle_bvh->signed_distance_gpu(
1564			n_elements, m_sdf.mesh_sdf_mode, positions, sdf_out, m_sdf.triangles_gpu.data(), false, m_stream.get()
1565		);
1566		CUDA_CHECK_THROW(cudaStreamSynchronize(m_stream.get()));
1567		/*
1568		std::vector<float> cpudensity(density.size());
1569		std::vector<vec3> cpupositions(n_elements);
1570		density.copy_to_host(cpudensity);
1571		cudaMemcpy(cpupositions.data(),positions,n_elements*12,cudaMemcpyDeviceToHost);
1572		for (int i=0;i<64;++i)
1573			printf("[%0.3f %0.3f %0.3f] -> %0.3f\n", cpupositions[i].x,cpupositions[i].y,cpupositions[i].z,cpudensity[i]);
1574		*/
1575		return density;
1576	}
1577	
1578	void Testbed::train_sdf(size_t target_batch_size, bool get_loss_scalar, cudaStream_t stream) {
1579		const uint32_t n_output_dims = 1;
1580		const uint32_t n_input_dims = 3;
1581	
1582		if (m_sdf.training.size >= target_batch_size) {
1583			// Auxiliary matrices for training
1584			const uint32_t batch_size = (uint32_t)std::min(m_sdf.training.size, target_batch_size);
1585	
1586			// Permute all training records to de-correlate training data
1587			linear_kernel(
1588				shuffle<vec3>,
1589				0,
1590				stream,
1591				m_sdf.training.size,
1592				1,
1593				m_training_step,
1594				m_sdf.training.positions.data(),
1595				m_sdf.training.positions_shuffled.data()
1596			);
1597			linear_kernel(
1598				shuffle<float>,
1599				0,
1600				stream,
1601				m_sdf.training.size,
1602				1,
1603				m_training_step,
1604				m_sdf.training.distances.data(),
1605				m_sdf.training.distances_shuffled.data()
1606			);
1607	
1608			GPUMatrix<float> training_target_matrix(m_sdf.training.distances_shuffled.data(), n_output_dims, batch_size);
1609			GPUMatrix<float> training_batch_matrix((float*)(m_sdf.training.positions_shuffled.data()), n_input_dims, batch_size);
1610	
1611			auto ctx = m_trainer->training_step(stream, training_batch_matrix, training_target_matrix);
1612	
1613			m_training_step++;
1614	
1615			if (get_loss_scalar) {
1616				m_loss_scalar.update(m_trainer->loss(stream, *ctx));
1617			}
1618		}
1619	}
1620	
1621	void Testbed::training_prep_sdf(uint32_t batch_size, cudaStream_t stream) {
1622		if (m_sdf.training.generate_sdf_data_online) {
1623			m_sdf.training.size = batch_size;
1624			m_sdf.training.positions.enlarge(m_sdf.training.size);
1625			m_sdf.training.positions_shuffled.enlarge(m_sdf.training.size);
1626			m_sdf.training.distances.enlarge(m_sdf.training.size);
1627			m_sdf.training.distances_shuffled.enlarge(m_sdf.training.size);
1628	
1629			generate_training_samples_sdf(m_sdf.training.positions.data(), m_sdf.training.distances.data(), batch_size, stream, false);
1630		}
1631	}
1632	
1633	// set scale_existing_results_factor=0. to reset any existing results; set it to 1.0 to accumulate more samples onto existing results
1634	// set it to a fraction near 1 to use a sliding EMA
1635	// if blocking is false, then this returns the iou from the *last* call
1636	double Testbed::calculate_iou(uint32_t n_samples, float scale_existing_results_factor, bool blocking, bool force_use_octree) {
1637		cudaStream_t stream = m_stream.get();
1638		uint32_t countercpu[8];
1639		m_sdf.iou_counter.enlarge(8);
1640		if (!blocking) { // when not blocking, returns data from the *last* run, then kicks off work to accumulate some more samples
1641			cudaMemcpy(countercpu, m_sdf.iou_counter.data(), 8 * 4, cudaMemcpyDeviceToHost);
1642		}
1643	
1644		if (scale_existing_results_factor < 1.f) {
1645			linear_kernel(scale_iou_counters_kernel, 0, stream, 8, m_sdf.iou_counter.data(), scale_existing_results_factor);
1646		}
1647		while (n_samples > 0) {
1648			uint32_t batch_size = std::min(uint32_t(128 * 128 * 128), n_samples);
1649			m_sdf.training.size = batch_size;
1650			n_samples -= batch_size;
1651			m_sdf.training.positions.enlarge(m_sdf.training.size);
1652			m_sdf.training.distances.enlarge(m_sdf.training.size);          // we use this buffer for the GT distances
1653			m_sdf.training.distances_shuffled.enlarge(m_sdf.training.size); // we use the shuffled output for the output of inference
1654	
1655			generate_training_samples_sdf(m_sdf.training.positions.data(), m_sdf.training.distances.data(), (uint32_t)(batch_size), stream, true);
1656			GPUMatrix<float> positions_matrix((float*)m_sdf.training.positions.data(), 3, batch_size);
1657			GPUMatrix<float> distances_matrix(m_sdf.training.distances_shuffled.data(), 1, batch_size);
1658			m_network->inference(stream, positions_matrix, distances_matrix);
1659			auto* octree_ptr = (m_sdf.uses_takikawa_encoding || m_sdf.use_triangle_octree || force_use_octree) ? m_sdf.triangle_octree.get() :
1660																												 nullptr;
1661			linear_kernel(
1662				compare_signs_kernel,
1663				0,
1664				stream,
1665				batch_size,
1666				m_sdf.training.positions.data(),
1667				m_sdf.training.distances.data(),          //  ref
1668				m_sdf.training.distances_shuffled.data(), // model
1669				m_sdf.iou_counter.data(),
1670				octree_ptr ? octree_ptr->nodes_gpu() : nullptr,
1671				octree_ptr ? octree_ptr->depth() : 0
1672			);
1673		}
1674		if (blocking) {
1675			CUDA_CHECK_THROW(cudaMemcpyAsync(countercpu, m_sdf.iou_counter.data(), 8 * 4, cudaMemcpyDeviceToHost, stream));
1676			CUDA_CHECK_THROW(cudaStreamSynchronize(stream));
1677		}
1678	
1679		return countercpu[4] / double(countercpu[5]);
1680	}
1681	
