	uint32_t step_size = std::min(i, STEPS_INBETWEEN_COMPACTION);

	RaysSdfSoa& rays_current = m_rays[(double_buffer_index + 1) % 2];
	RaysSdfSoa& rays_tmp = m_rays[double_buffer_index % 2];
	++double_buffer_index;

